import "@radix-ui/themes/styles.css";
import { Box, ThemePanel, Container, Flex, Section, Heading, Link} from "@radix-ui/themes";
import './App.css';
import { useState } from "react";

const Navigation = () => {
    return (
        <Box>
            <Flex gap="4" direction="column">
            <Link href="#about" style={{color: "rgba(255, 255, 255, 0.73)"}}>About</Link>
            <Link href="#experience" style={{color: "rgba(255, 255, 255, 0.73)"}}>Experience</Link>
            <Link href="#projects" style={{color: "rgba(255, 255, 255, 0.73)"}}>Projects</Link>
            </Flex>
        </Box>
    )
}

export default Navigation;
